import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    def calculate_time_to_reach(from_pos, to_pos):
        return np.linalg.norm(to_pos - from_pos) / truck_speed

    def calculate_cumulative_distance_from_other_trucks(customer_position):
        other_trucks_distances = [np.linalg.norm(truck_position - customer_position) for truck_position in all_truck_pos if np.array_equal(truck_position, cur_truck_pos) == False]
        return sum(other_trucks_distances)

    def is_within_time_window(arrival_time, window):
        return window[0] <= arrival_time <= window[1]

    best_node = None
    min_score = float('inf')

    for idx, customer in enumerate(unvisited_customers):
        travel_time = calculate_time_to_reach(cur_truck_pos, customer)
        arrival_time = current_time + travel_time
        wait_time = max(0, time_windows[idx][0] - arrival_time)
        total_time = arrival_time + wait_time

        if is_within_time_window(arrival_time, time_windows[idx]):
            cumulative_distance_score = calculate_cumulative_distance_from_other_trucks(customer)
            time_penalty = total_time + (time_windows[idx][1] - total_time) * 0.1
            score = time_penalty + cumulative_distance_score * 0.05
        else:
            score = float('inf')  # Infeasible option

        if score < min_score:
            min_score = score
            best_node = idx

    return best_node
